/**
 * Gallery page - discovers and displays available designs.
 */
import { STLViewer } from './viewer.js';

// Design manifests - generated by scripts/generate_manifest.sh and
// scripts/generate_stls.sh respectively.
const DESIGNS_MANIFEST_URL = 'designs.json';
const STL_MANIFEST_URL = 'models/manifest.json';

const gallery = document.getElementById('gallery');
const tagFilter = document.getElementById('tag-filter');

let activeTags = new Set();
let allDesigns = [];

async function loadManifest() {
    let designs = [];

    // Primary: designs.json (lightweight, always generated)
    try {
        const resp = await fetch(DESIGNS_MANIFEST_URL);
        if (resp.ok) designs = await resp.json();
    } catch (_) {
        // manifest not generated yet
    }

    // Merge STL-specific manifest if available (has verified stlFiles paths)
    try {
        const resp = await fetch(STL_MANIFEST_URL);
        if (resp.ok) {
            const stlManifest = await resp.json();
            const stlBySlug = Object.fromEntries(stlManifest.map(d => [d.slug, d]));
            for (const design of designs) {
                if (stlBySlug[design.slug]) {
                    design.stlFiles = stlBySlug[design.slug].stlFiles;
                }
            }
            // Add any designs only in STL manifest
            for (const entry of stlManifest) {
                if (!designs.find(d => d.slug === entry.slug)) {
                    designs.push(entry);
                }
            }
        }
    } catch (_) {
        // STL manifest not generated yet
    }

    return designs;
}

function formatName(slug) {
    return slug.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

function collectTags(designs) {
    const tagCounts = {};
    for (const design of designs) {
        for (const tag of (design.tags || [])) {
            tagCounts[tag] = (tagCounts[tag] || 0) + 1;
        }
    }
    return Object.entries(tagCounts)
        .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]));
}

function renderTagFilter(tagCounts) {
    if (tagCounts.length === 0) return;

    tagFilter.hidden = false;
    tagFilter.innerHTML = '<span class="tag-filter-label">Filter by tag:</span>';

    for (const [tag, count] of tagCounts) {
        const btn = document.createElement('button');
        btn.className = 'tag-btn';
        btn.textContent = `${tag} (${count})`;
        btn.dataset.tag = tag;
        btn.addEventListener('click', () => toggleTag(tag, btn));
        tagFilter.appendChild(btn);
    }
}

function toggleTag(tag, btn) {
    if (activeTags.has(tag)) {
        activeTags.delete(tag);
        btn.classList.remove('active');
    } else {
        activeTags.add(tag);
        btn.classList.add('active');
    }
    filterGallery();
}

function filterGallery() {
    const cards = gallery.querySelectorAll('.design-card');
    cards.forEach(card => {
        if (activeTags.size === 0) {
            card.style.display = '';
            return;
        }
        const cardTags = JSON.parse(card.dataset.tags || '[]');
        const match = [...activeTags].some(t => cardTags.includes(t));
        card.style.display = match ? '' : 'none';
    });
}

function createCard(design) {
    const card = document.createElement('div');
    card.className = 'design-card';
    card.dataset.tags = JSON.stringify(design.tags || []);

    // 3D preview container
    const preview = document.createElement('div');
    preview.className = 'preview';
    card.appendChild(preview);

    // Info section
    const info = document.createElement('div');
    info.className = 'info';

    const heading = document.createElement('h3');
    heading.textContent = design.name;
    info.appendChild(heading);

    const meta = document.createElement('p');
    meta.className = 'meta';
    meta.textContent = design.description || '';
    info.appendChild(meta);

    // Tags display
    if (design.tags && design.tags.length > 0) {
        const tagsContainer = document.createElement('div');
        tagsContainer.className = 'card-tags';
        for (const tag of design.tags) {
            const span = document.createElement('span');
            span.className = 'card-tag';
            span.textContent = tag;
            span.addEventListener('click', () => {
                // Clicking a tag on a card activates that filter
                const filterBtn = tagFilter.querySelector(`[data-tag="${tag}"]`);
                if (filterBtn && !activeTags.has(tag)) {
                    toggleTag(tag, filterBtn);
                }
            });
            tagsContainer.appendChild(span);
        }
        info.appendChild(tagsContainer);
    }

    card.appendChild(info);

    // View mode selector + actions
    const actions = document.createElement('div');
    actions.className = 'actions';

    const select = document.createElement('select');
    select.className = 'btn';
    for (const mode of Object.keys(design.stlFiles)) {
        const opt = document.createElement('option');
        opt.value = mode;
        opt.textContent = formatName(mode);
        select.appendChild(opt);
    }
    actions.appendChild(select);

    const editLink = document.createElement('a');
    editLink.className = 'btn btn-primary';
    editLink.href = `editor.html?design=${design.slug}`;
    editLink.textContent = 'Open in Editor';
    actions.appendChild(editLink);

    card.appendChild(actions);

    // Initialize 3D viewer
    requestAnimationFrame(() => {
        const viewer = new STLViewer(preview, {
            modelColor: 0x4a9eff,
        });
        viewer.startAnimation();

        // Try loading the default STL
        const defaultMode = Object.keys(design.stlFiles)[0];
        loadModel(viewer, design.stlFiles[defaultMode], preview);

        select.addEventListener('change', () => {
            loadModel(viewer, design.stlFiles[select.value], preview);
        });
    });

    return card;
}

async function loadModel(viewer, stlUrl, container) {
    try {
        await viewer.loadSTL(stlUrl);
    } catch (_) {
        // STL not generated yet - show placeholder message
        if (!container.querySelector('.placeholder')) {
            const placeholder = document.createElement('div');
            placeholder.className = 'placeholder';
            placeholder.style.cssText = `
                position: absolute; top: 50%; left: 50%;
                transform: translate(-50%, -50%);
                text-align: center; color: #666; font-size: 0.85rem;
                pointer-events: none;
            `;
            placeholder.innerHTML = 'STL not generated yet.<br>Use the Editor to render, or run the generation script.';
            container.style.position = 'relative';
            container.appendChild(placeholder);
        }
    }
}

async function init() {
    allDesigns = await loadManifest();
    gallery.innerHTML = '';

    if (allDesigns.length === 0) {
        gallery.innerHTML = '<div class="loading">No designs found. Add .scad files to the designs/ directory.</div>';
        return;
    }

    // Build tag filter
    const tagCounts = collectTags(allDesigns);
    renderTagFilter(tagCounts);

    for (const design of allDesigns) {
        gallery.appendChild(createCard(design));
    }
}

init();
